-- ── havenweb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Haven is a free, open-source, self-hosted blogging platform for sharing private posts, photos and updates with a hand-picked audience of friends and family, with no ads or trackers.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$havenweb Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Haven (havenweb.org) offers in 2026: private self-hosted blogging, pricing, key features, pros and cons, and the best alternatives to explore.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Haven, published at havenweb.org, is a self-hostable private blogging platform built as a deliberate alternative to mainstream social media. Rather than posting to a public feed owned by a large company, a Haven user runs their own small website that only the people they explicitly invite can see. The project's tagline captures the pitch directly: your Haven is private, and unlike a public blog or a social network post, search engines and outside companies cannot read what gets published there. The software combines a simple posting interface for writing text, sharing photos and formatting posts in markdown with a built-in private RSS reader, so a Haven owner can both publish to their own small circle and follow other people's Haven sites in one place. Every connection between a visitor's browser and a Haven server is encrypted over HTTPS, and there is intentionally no way to make a Haven public to the entire internet; access is granted account by account to the specific people the owner chooses. Haven was created by an independent developer who wanted a private, low-friction way to share family photos with relatives, and who had grown frustrated with running WordPress for that purpose because of its complexity, plugin maintenance overhead and constant exposure to comment spam and security patching. That frustration led to a from-scratch, deliberately minimal piece of software optimized for exactly one job: quiet, ad-free, algorithm-free sharing with people you already know and trust, rather than growth, engagement or public reach. The project became publicly known after a Show HN post on Hacker News that pitched Haven as a way to run a private website to share with only the people you choose, and it has continued to be maintained and iterated on by its creator and a small community of contributors since. Haven has no venture funding, no acquisition history and no company behind it in the traditional SaaS sense; it is best understood as an independent open-source side project distributed under the MIT license, with source code hosted publicly on GitHub under the havenweb organization. Because there is no corporate parent, there are no employee counts, headquarters or investor rounds to report, and the project's sustainability rests on its creator continuing to maintain the codebase and offer optional paid hosting rather than on outside capital. Technically, Haven runs as a lightweight, self-hosted web application that its creator has specifically designed to run comfortably on modest infrastructure, including a Raspberry Pi sitting on a home network or a small cloud virtual machine on a provider such as Amazon Web Services. Installation is most commonly done through Docker, which packages the application and its dependencies so an owner does not need deep systems administration experience to get a private site running. Because each Haven instance is single-tenant, one server runs exactly one person's or one family's Haven rather than pooling many unrelated users onto shared infrastructure, which is part of how the project preserves both privacy and predictable performance. For people who do not want to manage a server themselves, the project offers an official hosted option: a dedicated virtual server running only that customer's Haven instance, priced at five dollars per month, plus a fully managed hosting tier for people who want the operational burden handled entirely by someone else. Core features center on the writing and reading experience rather than social mechanics. The posting interface supports markdown with a live preview, so users can format text, embed images and structure longer posts without needing to know HTML. Visibility is controlled per account, meaning the owner explicitly creates a login for each friend or family member who should have access, rather than relying on a public link that could be forwarded outside the intended circle. Followers can subscribe to a private RSS feed unique to that Haven, and Haven itself bundles a reader so an owner can follow other people's Havens or traditional RSS feeds inside the same interface they use to publish their own updates. There is no advertising, no algorithmic feed, no public discovery mechanism and no tracking of visitors, which is a conscious design choice rather than an oversight; the entire point of the product is to remove the incentives that push mainstream platforms toward engagement-maximizing design. In terms of audience, Haven is aimed squarely at privacy-conscious individuals and families who want to share photos, life updates or writing with a specific, known group of people, such as extended family scattered across different cities, close friend groups or small private communities, without those updates being visible to search engines, advertisers or the general public. It appeals particularly to technically comfortable users who are willing to run Docker or manage a small VPS in exchange for full control over their data, though the paid hosting tier lowers that bar considerably for less technical users. Competitively, Haven sits in a different niche than mainstream blogging platforms like WordPress.com or Substack, which are built for public reach and, in Substack's case, monetization through paid subscriptions; Haven explicitly rejects that public-by-default model. It also differs from private social sharing done through Facebook groups, Instagram Close Friends or Google Photos shared albums, all of which route the sharing through a large company's servers and business model. Haven's closest philosophical peers are other small, independent, self-hosted publishing tools aimed at digital minimalism and data ownership, and its main tradeoff versus those bigger platforms is exactly the one its creator intended: less reach and fewer built-in social features, in exchange for real privacy, no ads, and full ownership of both the software and the data it stores.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0f3533a6-b675-46c9-b835-af562ae15087';

