-- ── HedgeDoc ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HedgeDoc is a free, open-source, self-hosted markdown editor for real-time collaborative note-taking, with presentation mode, revision history and permission controls.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (free, self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HedgeDoc Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what HedgeDoc offers in 2026: open-source collaborative markdown editing, self-hosting, key features, pros and cons, and the best alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HedgeDoc is a free, open-source, self-hosted platform for real-time collaborative markdown editing, built for teams, communities and individuals who want a Google-Docs-style collaborative writing experience for markdown notes without handing their content to a third-party company. Multiple people can open the same note simultaneously and see each other's edits appear live, making it a popular choice for meeting notes, technical documentation, workshop hackpads and conference note-taking, especially within open-source, developer and hacker communities that already prefer markdown and self-hosted tooling. The project's history is unusually tangled for open-source software and is worth explaining because it directly shapes what HedgeDoc is today. The lineage traces back to a collaborative markdown editor originally developed under the name HackMD, created primarily by developers Max Wu and Yukai Huang, which existed both as an open-source codebase and, eventually, as a commercial hosted product also called HackMD. To resolve the confusion between the open community codebase and the commercial HackMD product, the open-source project was renamed CodiMD in June 2018 and continued development under the AGPLv3 license as a community-maintained fork, separate from the HackMD company's own commercial roadmap; a hard fork of the CodiMD codebase was created into its own GitHub organization by community maintainers, while the original HackMD team continued maintaining a separate CodiMD-named repository under its own organization for a period. In 2020, the community project renamed itself again, this time to HedgeDoc, specifically to avoid ongoing naming confusion with yet another unrelated project also using the CodiMD name, and HedgeDoc has been the project's identity since. Throughout all of these renamings, the software has remained a community-driven open-source project rather than a venture-backed company; there is no HedgeDoc corporate entity, no funding history, no acquisition and no headquarters to report, and the project is maintained by volunteer contributors coordinating through its GitHub organization. Because of this lineage, HedgeDoc's earliest commits and public availability trace back to around 2016 under the CodiMD name, even though the HedgeDoc name itself only dates to 2020. Technically, HedgeDoc is a self-hosted web application distributed under the AGPL 3.0 license, with its complete source code publicly available on GitHub. It is deliberately lightweight: the project explicitly advertises that it runs smoothly even on a Raspberry Pi, and it is commonly deployed via a pre-configured Docker image or a ready-made server bundle, making it accessible to individuals and small teams without a dedicated infrastructure team. Because there is no hosted commercial SaaS version officially operated by the HedgeDoc project itself in the way HackMD's commercial product is, using HedgeDoc means either self-hosting the open-source software on your own server or finding a third-party host running an instance, which is a meaningfully different distribution model than most commercial note-taking tools. Core features center on real-time collaboration: multiple users can edit the same document simultaneously with changes syncing live across all connected sessions, and every note tracks its revision history so past versions can be reviewed or restored. Beyond plain text editing, HedgeDoc supports rendering of diagrams and graphs directly from markdown syntax, and it includes a presentation mode built on the open-source reveal.js library, letting a written markdown note be instantly turned into a slide deck for live presentations without a separate tool. Access control is handled through a permission system that lets a note's owner decide who can view or edit it, ranging from fully private notes to notes shared with specific collaborators to notes that are freely editable by anyone with the link, giving instances flexibility for both tightly controlled internal documentation and open collaborative hackpad-style use. The entire interface runs in a standard web browser with no client software installation required for end users, only for whoever administers the server. There is no traditional pricing structure to speak of because HedgeDoc has no commercial tiers, subscriptions or paid feature gates; the software itself is entirely free, and the only cost a user incurs is whatever server or hosting infrastructure they choose to run it on, which can range from literally free (a spare Raspberry Pi already on a home network) to whatever a cloud VM costs per month. HedgeDoc's target audience is technically comfortable teams, open-source communities, developer groups, universities, hacker and maker spaces, and privacy- or self-hosting-conscious individuals who want collaborative markdown editing without routing their notes through a third-party commercial service, plus organizations with data residency or compliance requirements that make self-hosting attractive or mandatory. Competitively, HedgeDoc sits closest to the commercial HackMD product it originally diverged from, as well as to other real-time collaborative editors like Etherpad, and to broader note-taking and documentation tools like Notion or Google Docs, though those alternatives are markdown-optional, hosted-only, closed-source commercial products rather than markdown-first, self-hostable, AGPL-licensed open-source software. HedgeDoc's core differentiation is precisely that combination: it is free, it is fully open source, it can be run entirely on infrastructure the user controls, and it is purpose-built around markdown and developer-friendly workflows like slide generation from notes, rather than being a general-purpose document editor that happens to support markdown as one input format among many.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6c79fd04-1ff8-447b-b662-4ad9e3fff565';

