-- ── Height ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Height was a fast, keyboard-driven, AI-assisted project management tool for engineering teams; the service was discontinued and shut down permanently on September 24, 2025.$q$, short_description),
  pricing_model = COALESCE($q$Discontinued (formerly Freemium)$q$, pricing_model),
  starting_price = COALESCE($q$Service discontinued$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Height Review 2026: Features, Pricing and Alternatives (Discontinued)$q$, seo_title),
  seo_meta_description = COALESCE($q$Height.app shut down in September 2025. Read our review of its features, pricing history, founders and the best alternatives to consider instead.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Height was a project management and issue-tracking tool built for software teams, notable for a fast, keyboard-driven interface and, in its later years, for embedding AI directly into project management workflows rather than bolting AI on as an afterthought. The company was founded in 2018 by Michael Villar, who served as CEO, and was headquartered in New York City. Before starting Height, Villar had already been through a notable prior exit: he co-founded Kickoff, a productivity company that was acquired by Stripe in 2013, and he subsequently worked as an early product designer and full-stack engineer at Stripe, where he helped build widely used products including Stripe Checkout, Stripe's iPhone app and Stripe Atlas. That background shaped Height's product philosophy toward tight, fast, engineering-team-friendly tooling rather than a broad, generalist project management suite. Height raised institutional funding, including a 14 million dollar Series A led by Redpoint Ventures announced in 2021, bringing the company's total disclosed funding to roughly 18.3 million dollars over its lifetime; it was not, based on available public information, a Y Combinator company. As a product, Height distinguished itself from heavier competitors like Jira and Asana through speed and a UI built around command-palette navigation, bulk editing and pervasive keyboard shortcuts, an approach the company positioned as noticeably snappier than the sluggish feel some users associated with larger, more established tools. Height's most distinctive later-stage feature was its AI assistant, which had full context on a team's project data and could summarize task history, draft task descriptions and surface likely blockers directly inside the workflow rather than as a generic chatbot layered on top. For engineering teams specifically, Height offered AI-driven bug triage, in which incoming bug reports could be automatically assessed for likely priority based on keywords and context and then routed to the appropriate engineer or team, reducing the manual triage overhead that many engineering teams handle by hand. The product's free tier was notably generous for its category, supporting up to five users with unlimited tasks and lists and full access to AI features at no cost, which was one of the more permissive free plans among project management tools at the time. Paid pricing sat at 8.50 dollars per user per month for the Teams tier and 14 dollars per user per month for the Business tier, with Height integrating with common tools in the engineering and design toolchain, including Figma, as part of its workflow. In March 2025, after seven years of operation, Height announced that it would shut down, with CEO Michael Villar describing the decision as one of the hardest he had to make; the company gave existing customers a runway before the shutdown and the service's final day of operation was September 24, 2025. Public reporting at the time framed the closure around Height doubling down on a new direction in autonomous project management before ultimately deciding to wind the product down entirely rather than pivot the existing product; there is no publicly reported acquisition of Height by another company, and no indication that the Height product, brand or codebase continued operating under new ownership after the shutdown date. As of today, Height.app is not available as an active product, and prospective customers researching Height should treat any pricing, feature or trial information as historical rather than current, since new signups and continued service are no longer possible through the company's own website or infrastructure. For historical and comparative purposes, Height's target audience was software engineering teams and fast-moving startups that wanted a lighter-weight, faster, more keyboard-centric alternative to Jira, Linear or Asana, with AI-assisted triage and task management layered directly into the core workflow rather than treated as a bolt-on feature. Competitively during its lifetime, Height was most frequently compared to Linear, Jira, Asana, ClickUp and Notion's project management features, and it differentiated itself primarily on raw interface speed, keyboard-first interaction design, and how deeply its AI assistant was integrated into everyday task and bug management rather than positioned as a separate add-on module. Teams that previously relied on Height for project management have needed to migrate to an alternative tool since the September 2025 shutdown, and Height's closure is frequently cited in industry commentary as an example of how even well-funded, well-reviewed developer tools can fail to reach sustainable scale in a crowded project management market dominated by entrenched incumbents like Jira, Asana and the fast-growing Linear.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '711daa05-d514-411e-aebb-2efdcb754ed0';

