INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Private, invite-only publishing$q$, $q$Every Haven site is invisible to the public internet by design; the owner creates an account for each person who should have access, and there is no way to open the site to everyone.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Markdown editor with live preview$q$, $q$Posts are written in markdown with a live preview pane, making it easy to format text and embed photos without touching HTML.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Built-in RSS reader$q$, $q$Owners can follow other people's Havens or traditional blogs and RSS feeds from inside the same interface they use to publish their own posts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Private RSS feeds for followers$q$, $q$Invited followers get a private RSS feed unique to that Haven so they can keep up with new posts in their own feed reader.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Self-hosted, single-tenant architecture$q$, $q$Each Haven instance runs on infrastructure the owner controls, from a home Raspberry Pi to a small cloud VM, keeping data off shared third-party servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Docker-based installation$q$, $q$The project ships with a Docker deployment path, making setup manageable without deep systems administration experience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$HTTPS encryption by default$q$, $q$All traffic between a visitor's browser and the Haven server is encrypted, so posts cannot be intercepted in transit.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$No ads or tracking$q$, $q$Haven contains no advertising, analytics trackers or engagement-optimized algorithmic feed, keeping the focus on the people you actually invited.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Completely free and open source, with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Genuinely private by design, with no public visibility option and no tracking or ads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Lightweight enough to run on very cheap hardware like a Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Simple, focused feature set that avoids the complexity and spam issues of platforms like WordPress$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Low-cost official hosting option for people who do not want to self-host$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Requires comfort with Docker or a willingness to pay for hosting to get started$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$No built-in monetization tools, unlike public blogging platforms such as Substack$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Small, independent project with no dedicated support team or enterprise SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Limited discovery: because it is intentionally private, there is no way to grow an audience beyond people you personally invite$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Feature set is minimal compared to full-featured CMS platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$What is Haven used for?$q$, $q$Haven is used to run a private, self-hosted blog or photo-sharing site that only people you explicitly invite can see, such as extended family or a close friend group.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Is Haven free?$q$, $q$Yes, Haven's source code is free and open source under the MIT license. There is also an optional hosted plan starting at 5 dollars a month for people who do not want to manage their own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Do I need technical skills to run Haven?$q$, $q$Self-hosting Haven with Docker is easiest for people comfortable with basic server administration. Less technical users can use Haven's paid or fully managed hosting instead.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Can anyone find my Haven through Google?$q$, $q$No. Haven has no public visibility mode; only accounts the owner creates can access the site, and it is not designed to be indexed or discoverable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Who created Haven?$q$, $q$Haven was created by an independent developer who wanted a simpler, private alternative to WordPress for sharing family photos, and it has been maintained as an open-source project since.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$How is Haven different from Substack or WordPress.com?$q$, $q$Substack and WordPress.com are built for public, discoverable publishing and, in Substack's case, monetization. Haven is built for the opposite use case: small, private, ad-free sharing with people you already know.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Sharing family photos privately$q$, $q$A family member sets up Haven to post photos and updates that only relatives with an account can see, avoiding public social media entirely.$q$, $q$Families and extended relatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Private journaling for a small circle$q$, $q$A writer uses Haven to publish personal reflections or updates to a small group of trusted friends without exposing them to a public audience.$q$, $q$Individuals and close friend groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Ad-free alternative to social media$q$, $q$Privacy-conscious users replace public social feeds with a self-hosted Haven to control exactly who sees their posts and to avoid ads and tracking.$q$, $q$Privacy-focused individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Self-hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open source under the MIT license","Full control over your own server","Docker-based deployment","No feature restrictions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Hosted$q$, $q$$5/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated virtual server for your Haven only","No self-hosting required","Same features as self-hosted"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$Fully Managed$q$, $q$Custom$q$, $q$Contact for pricing$q$, NULL, $q$["Setup and maintenance handled for you","Best for non-technical users"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Haven is an open-source, self-hosted blogging platform built for people who want to share photos and updates privately with a specific group of friends or family rather than post publicly. It was created by an independent developer who was frustrated with WordPress's complexity and spam problems and wanted a simpler, private way to share family photos.$q$, $q$Unlike a public blog, a Haven site has no way to be made visible to the general internet. Every visitor needs an account the owner creates for them, every connection is encrypted, and there is no advertising, tracking or algorithmic feed anywhere in the product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Haven includes a markdown post editor with live preview, per-account access control so the owner decides exactly who can see the site, a private RSS feed for followers, and a built-in RSS reader so owners can follow other Havens or outside blogs from the same interface.$q$, $q$Because each Haven is single-tenant and runs on infrastructure the owner controls or rents, it can run on hardware as small as a Raspberry Pi or a low-cost cloud virtual machine, and it is most commonly deployed using Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Haven's source code is free and open source under the MIT license, so anyone comfortable with Docker can self-host it at no cost beyond their own server. For people who prefer not to manage infrastructure themselves, Haven also offers an official hosted plan on a dedicated virtual server for five dollars per month, plus a fully managed hosting option for those who want setup and maintenance handled for them.$q$, $q$There are no tiered feature plans; the paid options are purely about who manages the hosting, not about unlocking additional functionality.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0f3533a6-b675-46c9-b835-af562ae15087', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Dead man's switch monitoring$q$, $q$Jobs ping Healthchecks on success; if a ping is missed within the expected window, an alert fires automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Cron expression scheduling$q$, $q$Checks can be defined with simple periods or full cron syntax, with a configurable grace period for minor timing drift.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Timing pings$q$, $q$Optional start/success pings let Healthchecks report how long a job actually took to run, surfacing slow jobs as well as failed ones.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Multi-channel alerting$q$, $q$Notifications can go out via email, SMS, WhatsApp, phone call, Slack, PagerDuty, Opsgenie, Microsoft Teams or webhooks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Self-hosting option$q$, $q$The complete Django/Python codebase is open source on GitHub, so the exact hosted product can be run on your own servers for free.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Projects and team access$q$, $q$Checks can be organized into projects with shared team access and role-based permissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Ping logs and history$q$, $q$Every check keeps a log of recent pings so you can audit exactly when a job ran, succeeded or failed.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Read-only and badge URLs$q$, $q$Status badges and read-only API endpoints make it easy to surface check status on dashboards or status pages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Generous free tier (20 checks) that is genuinely usable, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Fully open source with a self-hosting option for teams that need data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Simple, transparent, developer-friendly pricing with no hidden limits$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Wide range of alert integrations covering most on-call and chat tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Run and maintained by a founder with a long, public track record of reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$As a one-person company, support responsiveness can vary compared to larger vendors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Higher check volumes require paid plans, which can add up for larger fleets of jobs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$SMS, WhatsApp and phone call alerts are credit-limited even on paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$No built-in uptime/website monitoring; it is focused specifically on scheduled job monitoring$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Self-hosting requires managing your own Django/Python deployment and updates$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$What does Healthchecks.io actually monitor?$q$, $q$It monitors whether your cron jobs, scheduled scripts and background tasks actually run on time, using a dead man's switch: your job pings a URL on success, and Healthchecks alerts you if that ping doesn't arrive.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Is Healthchecks.io free?$q$, $q$Yes, the Hobbyist plan is free and supports up to 20 checks. Paid plans start at 5 dollars a month for supporters and scale to 20 and 80 dollars a month for higher check limits and SMS/call credits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Can I self-host Healthchecks.io?$q$, $q$Yes. The full source code is open source under a BSD license and available on GitHub, so you can run the same software on your own servers instead of using the hosted SaaS.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Who built Healthchecks.io?$q$, $q$It was built and is still run by Pēteris Caune, a Python developer based in Valmiera, Latvia, as a one-person bootstrapped company that launched the service in July 2015.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Do open-source projects get free access?$q$, $q$Yes, Healthchecks.io offers the Business plan free of charge to open-source projects and registered non-profits on request.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$How is Healthchecks.io different from uptime monitors like Pingdom?$q$, $q$Uptime monitors check from the outside whether a website responds. Healthchecks.io instead relies on your own jobs checking in, which catches silent failures like a cron job that stops running entirely rather than just a website going down.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Monitoring cron jobs and backups$q$, $q$A developer sets up a check for each nightly backup or ETL script so they are alerted immediately if a job silently stops running.$q$, $q$Developers and sysadmins$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Monitoring background workers in production$q$, $q$An engineering team pings Healthchecks from queue workers and scheduled application tasks to catch silent failures before customers notice.$q$, $q$DevOps and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Compliance-driven self-hosted monitoring$q$, $q$An organization with data residency requirements self-hosts the open-source Healthchecks codebase to monitor internal jobs without sending data to a third party.$q$, $q$Regulated or security-conscious teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Hobbyist$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 20 checks","100 log entries per check","Unlimited email alerts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Supporter$q$, $q$$5/month$q$, $q$Monthly$q$, NULL, $q$["Up to 20 checks","100 log entries per check","Supports development of the service"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Business$q$, $q$$20/month ($16/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 100 checks","1,000 log entries per check","50 SMS and WhatsApp credits","20 phone call credits","Email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$Business Plus$q$, $q$$80/month ($64/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 1,000 checks","1,000 log entries per check","500 SMS and WhatsApp credits","100 phone call credits","Priority email support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Healthchecks.io monitors cron jobs and other periodic or background tasks using the dead man's switch pattern: your job pings a unique URL every time it runs, and Healthchecks alerts you the moment a ping fails to arrive on schedule. It was created in 2015 by Latvian developer Pēteris Caune, who still runs it as a one-person, bootstrapped SaaS business.$q$, $q$The full codebase is open source under a BSD license and available on GitHub, so teams can either use the hosted service at healthchecks.io or self-host the exact same software on their own infrastructure at no cost.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Each monitored job gets a unique ping URL, a configurable schedule (simple interval or cron expression) and a grace period before an alert fires. Timing pings let you track how long a job takes to run, not just whether it ran.$q$, $q$Alerts route through email (always free), SMS, WhatsApp, phone calls, Slack, PagerDuty, Opsgenie, Microsoft Teams and generic webhooks, making it straightforward to plug Healthchecks into an existing on-call or incident response workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free Hobbyist plan covers 20 checks with 100 log entries each, enough for many solo developers to never pay. Paid tiers scale up from there: Business at 20 dollars a month (100 checks, SMS/call credits) and Business Plus at 80 dollars a month (1,000 checks, higher credit allowances), both discounted roughly 20 percent on annual billing.$q$, $q$Open-source projects and non-profits can request the Business plan free of charge, and the company donates 5 percent of monthly revenue back to open-source dependencies.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24aa6862-35d5-4811-b145-17e35cd64036', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$GraphQL API and React SDKs$q$, $q$The full platform, EHR, scheduling, billing and telehealth, is exposed through the same GraphQL API Healthie's own product teams use, with pre-built React SDKs to speed up integration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Live telehealth with group sessions$q$, $q$Built-in video visits support both one-on-one and group telehealth sessions, with group telehealth available on the Plus tier and above.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Integrated scheduling and payments$q$, $q$Calendar-synced appointment scheduling paired with Stripe-powered payment processing for billing clients directly.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Food and lifestyle journaling$q$, $q$Client-facing journaling tools rooted in Healthie's nutrition and dietitian heritage, useful for tracking diet, symptoms and lifestyle data over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Insurance billing and eFax$q$, $q$CMS-1500 claim generation, ClaimMD clearinghouse integration and dedicated inbound/outbound fax lines support practices that bill insurance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Care plans and goal tracking$q$, $q$Structured care plans and goal-tracking tools let providers document and monitor progress across longitudinal treatment relationships.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Free native mobile apps$q$, $q$Dedicated iOS and Android apps, free for both providers and clients, support on-the-go scheduling, messaging and journaling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$ONC certification and HIPAA/PCI compliance$q$, $q$Healthie is an ONC Certified EHR with HIPAA and PCI compliance built into every plan, a requirement for many digital health partnerships.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$API-first architecture lets digital health companies fully embed EHR infrastructure into their own branded product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Serves a wide range of specialties (nutrition, therapy, coaching, chronic care) under one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Affordable entry-level pricing compared to legacy enterprise EHR systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$ONC certification and built-in HIPAA/PCI compliance reduce vendor-evaluation friction$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Free native mobile apps for both providers and clients$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$API access is largely gated to Group and higher-tier or Enterprise plans, adding cost for developer-first use cases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Per-client pricing on lower tiers can get expensive quickly as a practice grows past the Core plan's 10-client cap$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Insurance billing add-ons like ClaimMD carry additional monthly fees$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$As a broad multi-specialty platform, some workflows may need more configuration than a niche single-specialty EHR$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Team features like shared calendars and internal chat only unlock on the Group plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$What is Healthie used for?$q$, $q$Healthie is used as an EHR and practice management platform for scheduling, charting, billing, telehealth and patient engagement, either as a ready-made app for individual practitioners or as API infrastructure for digital health companies building their own product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Does Healthie have an API?$q$, $q$Yes, Healthie exposes its entire platform through a GraphQL API, the same one used internally by Healthie's own engineering team, along with pre-built React SDKs for faster integration.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$How much does Healthie cost?$q$, $q$Plans start at 19 dollars a month for the Core tier (up to 10 clients) and scale to 49, 129 and 149-dollars-plus per month for the Essentials, Plus and Group tiers, with roughly 10 percent savings on annual billing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Is Healthie HIPAA compliant?$q$, $q$Yes, Healthie is HIPAA and PCI compliant across every plan and is an ONC Certified EHR.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Who founded Healthie?$q$, $q$Healthie was founded in 2016 by CEO Erica Jain and CTO Cavan Klinsky, and is headquartered in New York City.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Does Healthie support insurance billing?$q$, $q$Yes, Healthie supports CMS-1500 insurance claim generation natively, with ClaimMD clearinghouse integration available as a paid add-on starting on the Essentials plan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Solo practitioner practice management$q$, $q$A dietitian or therapist in private practice uses Healthie's Core or Essentials plan to handle scheduling, telehealth, billing and client charting in one HIPAA-compliant app.$q$, $q$Solo and small-group healthcare practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Embedded EHR for digital health startups$q$, $q$A virtual-first care startup builds its own branded patient app on top of Healthie's GraphQL API and React SDKs instead of building EHR infrastructure from scratch.$q$, $q$Digital health founders and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Multi-provider group practice operations$q$, $q$A group practice with multiple clinicians uses the Group plan for shared calendars, internal staff chat, roles and permissions, and centralized billing across providers.$q$, $q$Multi-clinician healthcare organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Core$q$, $q$$19/month ($18/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10 active clients","Scheduling, payments, charting, telehealth","Client portal and mobile app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Essentials$q$, $q$$49/month ($45/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 250 active clients","Free outbound fax","Custom forms and CMS-1500 claims","Group messaging","ClaimMD integration available as add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Plus$q$, $q$$129/month ($115/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited active clients","Group telehealth","Online programs","Dedicated inbound/outbound eFax"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$Group$q$, $q$From $149/month ($135/month billed annually), plus $50/month per additional clinician$q$, $q$Monthly or annual$q$, NULL, $q$["Shared calendar","Team member management","Roles and permissions","Internal staff chat","Dedicated support contact per provider"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Healthie is an API-first, ONC-certified EHR and practice management platform founded in 2016 by Erica Jain and Cavan Klinsky. It gives individual practitioners a ready-made app for scheduling, charting, billing and telehealth, while also exposing the entire platform through a GraphQL API for digital health companies that want to embed EHR infrastructure into their own branded product.$q$, $q$The company is headquartered in New York and has raised more than 42 million dollars from investors including TCV, Birchmere Ventures and Velvet Sea Ventures, serving more than 45,000 clinicians and 17 million patients across 25-plus longitudinal care specialties.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform covers scheduling, live video telehealth, Stripe-based payment processing, food and lifestyle journaling, customizable intake forms, care plans and goal tracking, secure messaging and CMS-1500 insurance claim generation, all wrapped in a free iOS and Android app for providers and clients.$q$, $q$Its defining feature is a GraphQL API, the same one Healthie's own engineers use internally, paired with pre-built React SDKs, letting digital health startups embed Healthie's EHR functionality directly into their own product rather than sending users to a separate portal.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Healthie prices primarily by active client count across four tiers: Core at 19 dollars a month (up to 10 clients), Essentials at 49 dollars a month (up to 250 clients), Plus at 129 dollars a month (unlimited clients), and Group starting at 149 dollars a month plus 50 dollars per additional clinician for multi-provider practices. Annual billing saves roughly 10 percent.$q$, $q$All plans include HIPAA and PCI compliance, core charting and secure messaging, while the GraphQL API and deeper integrations like ClaimMD or DoseSpot ePrescribing are available as add-ons, typically on Group and higher tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ca5d5be-9880-4ce7-94dd-56ab90d70f72', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocapture data collection$q$, $q$A single SDK snippet automatically records every user interaction, clicks, taps, page views, form submissions, without requiring engineers to manually write tracking code for each event.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive event definition$q$, $q$Analysts can define a new virtual event after the product has already shipped and immediately see historical data for it, rather than waiting for new data to accumulate.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Funnel and retention analysis$q$, $q$Standard product analytics views show where users drop off in multi-step flows and which cohorts keep returning over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Path analysis$q$, $q$Visualizes the actual sequences of steps users take through a product, surfacing unexpected navigation patterns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Account-level analytics$q$, $q$Rolls up individual user behavior to the account level, useful for B2B teams tracking engagement across an organization rather than a single user.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Session replay and heatmaps (add-on)$q$, $q$Optional add-on capability that records individual sessions and aggregates click/scroll behavior into heatmaps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Real-time alerts$q$, $q$Available on Pro and above, alerts notify teams the moment defined behavioral thresholds or anomalies occur.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Data warehouse integration$q$, $q$Premier-tier customers can sync Heap's captured event data directly into their own data warehouse for custom analysis.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocapture removes the need to manually instrument every tracking event in advance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive event definition means historical data is available immediately for newly defined metrics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Now backed by Contentsquare's resources and combined with its session replay and heatmap capabilities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Strong account-level analytics for B2B product teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Genuinely usable free tier for small teams and early-stage products$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$All paid tiers require a custom sales quote rather than transparent self-serve pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Session replay and heatmaps are add-ons rather than included by default$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocapturing everything can generate a large volume of raw data that requires cleanup to keep analysis manageable$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Post-acquisition roadmap and support are now tied to Contentsquare's broader strategy rather than an independent Heap-only focus$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Enterprise-oriented pricing model can be a poor fit for very small teams that outgrow the free tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$What does Heap do?$q$, $q$Heap is a product analytics platform that automatically captures every user interaction on a website or app using autocapture, letting teams define and analyze specific events retroactively instead of manually instrumenting tracking code in advance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Is Heap free?$q$, $q$Heap has a free tier that covers up to 10,000 monthly sessions with six months of data history. Paid tiers (Growth, Pro, Premier) require a custom quote based on session volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Who owns Heap now?$q$, $q$Heap was acquired by Contentsquare in a deal announced in September 2023 and completed in December 2023, and now operates as Heap by Contentsquare.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Who founded Heap?$q$, $q$Heap was founded in 2013 in Silicon Valley by Matin Movassate and Ravi Parikh, and was headquartered in San Francisco before its acquisition.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Does Heap include session replay?$q$, $q$Session replay and the associated heatmaps are available as an add-on on top of Heap's core analytics plans rather than included by default on every tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$How is Heap different from Mixpanel or Amplitude?$q$, $q$Heap's key differentiator is autocapture: it records all user interactions from the start and lets you define events retroactively, whereas Mixpanel and Amplitude have traditionally relied more on deliberate, upfront event instrumentation, though both have added autocapture-style options over time.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Product-led growth analysis$q$, $q$A product team uses Heap's autocapture and funnel analysis to find where users drop off during onboarding without having to predefine every tracked event in advance.$q$, $q$Product managers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$B2B account engagement tracking$q$, $q$A SaaS company rolls individual user behavior up to the account level to identify which customer accounts are at risk of churn based on declining engagement.$q$, $q$Customer success and B2B SaaS teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive feature adoption measurement$q$, $q$After shipping a new feature, an analyst defines a new event in Heap and immediately sees historical adoption data going back to before the feature was even announced, thanks to autocapture.$q$, $q$Data analysts and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 10,000 monthly sessions","6 months of data history","Core autocapture analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Growth$q$, $q$From approximately $3,600/year (custom quote)$q$, $q$Annual, custom$q$, NULL, $q$["Unlimited users and reports","Chart customization","CSV exports","12 months of data history"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Pro$q$, $q$Custom quote$q$, $q$Annual, custom$q$, NULL, $q$["Account-level analytics","Real-time alerting","Session replay available as add-on"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Premier$q$, $q$Custom quote$q$, $q$Annual, custom$q$, NULL, $q$["Data warehouse integration","Behavioral targeting","Dedicated customer success manager","Longest data retention"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Heap is a product analytics platform founded in 2013 by Matin Movassate and Ravi Parikh in San Francisco, built around autocapture: it records every user interaction on a web or mobile product automatically, so teams can define and query events retroactively instead of manually instrumenting tracking code in advance.$q$, $q$After raising roughly 216 million dollars and reaching a valuation near 960 million dollars as an independent company, Heap was acquired by Contentsquare in a deal announced in September 2023 and closed in December 2023, and now operates as Heap by Contentsquare within Contentsquare's broader experience analytics suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Autocapture is Heap's foundational feature: a single SDK snippet captures every click, tap, form submission and page view from day one, and teams define the specific events they care about after the fact, with data available retroactively. On top of that, Heap offers funnel analysis, retention analysis, path analysis and account-level analytics for B2B teams.$q$, $q$Session replay and heatmaps are available as an add-on for teams that want to pair Heap's quantitative event data with qualitative session recordings, and higher tiers add real-time alerting, data warehouse integration and behavioral targeting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Heap's Free plan is self-serve and covers up to 10,000 monthly sessions with six months of data history and no cost. Every paid tier above it, Growth, Pro and Premier, requires a custom sales quote based primarily on monthly session volume, with Growth reportedly starting around 3,600 dollars per year on an annual commitment.$q$, $q$Higher tiers progressively add unlimited users and reports, longer data retention, account-level analytics, real-time alerts, session replay as an add-on, data warehouse integration and a dedicated customer success manager on the top Premier tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Unlimited discussion channels, courses and events$q$, $q$Every plan, including the entry-level Build tier, includes unlimited discussion channels, structured online courses and event scheduling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Branded white-label mobile app$q$, $q$On the Scale plan, communities get their own fully branded mobile app in the App Store and Google Play rather than a generic shared app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Native payment processing$q$, $q$Built-in payments let creators charge for membership access directly, with declining transaction fees as customers move up plan tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Workflow automations$q$, $q$Automations trigger emails, DMs or actions based on member behavior, with limited workflows on Build and unlimited on Grow and Scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Custom landing pages$q$, $q$Brandable landing pages for marketing and signups are included on every plan, scaling from 1 page on Build to 50 on Scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Native video hosting$q$, $q$Built-in video hosting for courses and events, with hour allowances that scale from the Grow plan (50 hours) to Scale (200 hours).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Member directory$q$, $q$A searchable member directory helps community members find and connect with each other.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$API access and integrations$q$, $q$Grow and Scale plans include API access alongside integrations with tools like Zapier, Zoom and Google Calendar.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Bundles discussions, courses, events, landing pages and payments into one product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Transaction fees decline as customers move to higher plans, rewarding growth$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Branded, white-label mobile app option available for larger communities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Founder-led onboarding and live walkthroughs for new customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$14-day free trial with no credit card required on every plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Entry-level Build plan is capped at 350 members, which smaller creators may hit quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Transaction fees on top of Stripe's processing fees add up for high-volume paid communities on lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Branded mobile app is only available on the top Scale plan, priced significantly higher than Build or Grow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$API access is not available on the entry-level Build plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Annual commitment required to access the discounted per-month pricing on each tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$What is Heartbeat used for?$q$, $q$Heartbeat is used to run online communities, memberships, courses and events, combining discussions, payments, a member directory and optionally a branded mobile app in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$How much does Heartbeat cost?$q$, $q$Heartbeat has three plans: Build at 49 dollars a month, Grow at 149 dollars a month, and Scale at 849 dollars a month, each with a discount for annual billing and a 14-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Does Heartbeat take a cut of membership payments?$q$, $q$Yes, Heartbeat charges a transaction fee on payments processed through its built-in payment system, on top of Stripe's own fees: 5 percent on Build, 2.5 percent on Grow and 1.25 percent on Scale.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Does Heartbeat offer a branded mobile app?$q$, $q$Yes, a fully white-labeled, branded mobile app in the App Store and Google Play is included on the Scale plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Who founded Heartbeat?$q$, $q$Heartbeat was co-founded by CEO Murtaza Bambot and CTO Mayhul Arora, and the company is headquartered in New York City.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$How is Heartbeat different from Discord or a Facebook Group?$q$, $q$Unlike Discord or Facebook Groups, Heartbeat includes native payment processing, structured courses, a branded mobile app option and landing pages built specifically for running a monetized, owned community rather than a free social space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Paid creator memberships$q$, $q$A creator launches a paid membership community with discussions, exclusive content and events, charging members directly through Heartbeat's built-in payments.$q$, $q$Independent creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Cohort-based online courses$q$, $q$An instructor combines Heartbeat's course tools with live events and discussion channels to run a structured, cohort-based learning program.$q$, $q$Course creators and educators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Branded customer or member communities for businesses$q$, $q$A company on the Scale plan launches a fully white-labeled branded app to host its customer or member community under its own brand.$q$, $q$Businesses and larger membership organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Build$q$, $q$$49/month ($40/month billed annually, $490/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 350 members","5 automation workflows","1 custom landing page","Unlimited channels, courses and events","Member directory","Basic integrations (Zapier, Zoom, Google Calendar)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Grow$q$, $q$$149/month ($124/month billed annually, $1,490/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 5,000 members","Unlimited automation workflows","Auto-responder and DM rules","50 hours native video hosting","Up to 15 custom landing pages","API access","Priority support (1 business day)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$Scale$q$, $q$$849/month (approximately $766/month billed annually, $9,200/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited members","Branded white-label mobile app","Advanced analytics","Up to 50 custom landing pages","200 hours native video hosting","Dedicated onboarding expert","Same-day support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Heartbeat is an all-in-one community platform co-founded by CEO Murtaza Bambot and CTO Mayhul Arora and headquartered in New York City. It combines discussions, courses, events, a member directory, automations, landing pages and native payments into a single product for creators and businesses running paid or free membership communities.$q$, $q$The company says it is trusted by roughly 5,000 communities and emphasizes direct founder involvement in customer onboarding, offering live walkthroughs led personally by its founders.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include unlimited discussion channels, courses and events across all plans, a member directory, workflow automations, custom-brandable landing pages, native video hosting and built-in payment processing so creators do not need a separate billing tool.$q$, $q$The top Scale plan adds a fully white-labeled, branded mobile app that puts the community operator's own name and icon in the App Store and Google Play, along with advanced analytics and a dedicated onboarding specialist.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Heartbeat has three tiers, each with a 14-day free trial: Build at 49 dollars a month (350 members), Grow at 149 dollars a month (5,000 members, API access), and Scale at 849 dollars a month (unlimited members, branded mobile app). Annual billing discounts each tier.$q$, $q$In addition to the flat subscription, Heartbeat charges a declining transaction fee on payments processed through the platform, 5 percent on Build, 2.5 percent on Grow and 1.25 percent on Scale, on top of Stripe's standard processing fees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda2cde-3534-421f-9cdb-eac5fb45b0e6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Real-time collaborative editing$q$, $q$Multiple users can edit the same markdown note simultaneously, with changes syncing live across all connected sessions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Revision history$q$, $q$Every note keeps a history of past versions so changes can be reviewed or restored.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Presentation mode via reveal.js$q$, $q$Any markdown note can be instantly turned into a live slide presentation using the built-in reveal.js-powered presentation mode.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Diagrams and graphs from markdown$q$, $q$Supports rendering diagrams and graphs directly from markdown syntax without needing separate diagramming software.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Flexible permission system$q$, $q$Note owners control access on a spectrum from fully private to shared-with-specific-collaborators to freely editable by anyone with the link.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Lightweight self-hosted deployment$q$, $q$Runs comfortably on minimal hardware, including a Raspberry Pi, and deploys easily via Docker or a pre-configured server bundle.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$AGPL 3.0 open-source license$q$, $q$The complete source code is public on GitHub under the AGPL 3.0 license, ensuring transparency and community extensibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Browser-based interface$q$, $q$No client installation is required for end users; the entire editing experience runs in a standard web browser.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Completely free and open source with no commercial tiers or paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Genuinely lightweight and can run on minimal hardware like a Raspberry Pi$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Real-time collaboration and revision history rival commercial collaborative editors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Built-in presentation mode turns notes into slides without a separate tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Full data control for teams with self-hosting or compliance requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$No officially operated hosted SaaS version, so self-hosting or finding a third-party host is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$No dedicated commercial support team or SLA, since it is a volunteer-maintained project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Interface and feature set are more minimal than fully featured commercial note-taking tools like Notion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Setup and maintenance require some server administration knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$History of multiple renamings (HackMD to CodiMD to HedgeDoc) can create confusion when searching for documentation or older resources$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Is HedgeDoc free?$q$, $q$Yes, HedgeDoc is completely free and open source under the AGPL 3.0 license. There are no paid tiers; the only cost is whatever server infrastructure you use to host it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$What was HedgeDoc called before?$q$, $q$HedgeDoc was previously known as CodiMD, which itself was a community fork of the original HackMD open-source codebase. It was renamed CodiMD in 2018 and then HedgeDoc in 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Can I self-host HedgeDoc?$q$, $q$Yes, HedgeDoc is designed to be self-hosted, commonly via Docker, and is lightweight enough to run on hardware as small as a Raspberry Pi.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Does HedgeDoc support real-time collaboration?$q$, $q$Yes, multiple users can edit the same markdown note at the same time, with changes syncing live and full revision history available.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Can HedgeDoc create presentations?$q$, $q$Yes, HedgeDoc includes a built-in presentation mode powered by reveal.js that turns a markdown note directly into a slide deck.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Who maintains HedgeDoc?$q$, $q$HedgeDoc is maintained by a community of volunteer open-source contributors rather than a commercial company, coordinated through its GitHub organization.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Collaborative meeting and workshop notes$q$, $q$Teams and conference attendees use HedgeDoc as a shared hackpad to take collaborative notes in real time during meetings or workshops.$q$, $q$Teams, conferences and open-source communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Self-hosted technical documentation$q$, $q$Developer teams self-host HedgeDoc to write and collaboratively edit markdown documentation without relying on a third-party SaaS tool.$q$, $q$Engineering and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Markdown-based slide presentations$q$, $q$A presenter writes talk notes in markdown and uses HedgeDoc's built-in presentation mode to deliver a live slideshow directly from the note.$q$, $q$Educators, speakers and technical presenters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$Self-hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open source under AGPL 3.0","Full source code on GitHub","No feature restrictions","Runs via Docker or a server bundle"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HedgeDoc is a free, open-source, self-hosted platform for real-time collaborative markdown editing. Its lineage traces back to the HackMD open-source codebase around 2016, which was renamed CodiMD in 2018 to separate the community project from the commercial HackMD product, and then renamed again to HedgeDoc in 2020.$q$, $q$There is no company behind HedgeDoc; it is a volunteer-maintained, community-driven open-source project distributed under the AGPL 3.0 license, with no hosted commercial SaaS version operated by the project itself.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Multiple users can edit the same note simultaneously with live-syncing changes and full revision history. Notes support embedded diagrams and graphs, and a built-in presentation mode powered by reveal.js turns any markdown note into a slide deck.$q$, $q$A flexible permission system controls who can view or edit each note, from fully private to freely link-editable, and the whole platform is deliberately lightweight, running comfortably even on a Raspberry Pi via Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HedgeDoc has no commercial pricing tiers, subscriptions or paid feature gates. The software is entirely free and open source; the only cost is whatever hosting infrastructure a user chooses to run it on.$q$, $q$Because there is no official hosted SaaS product, using HedgeDoc requires either self-hosting it or finding a third-party-operated instance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c79fd04-1ff8-447b-b662-4ad9e3fff565', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Command-palette, keyboard-first navigation$q$, $q$Height's interface was built around keyboard shortcuts and a command palette for fast navigation and bulk editing, positioned against slower competitors like Jira.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$AI assistant with full project context$q$, $q$An integrated AI assistant could summarize task history, draft task descriptions and surface likely blockers using full context on a team's project data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$AI-driven bug triage$q$, $q$Incoming bug reports could be automatically evaluated for priority based on keywords and context, then routed to the appropriate engineer or team.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Generous free tier$q$, $q$Up to 5 users could use Height for free with unlimited tasks, lists and full AI features included, unusually generous for the project management category.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Bulk task editing$q$, $q$Teams could select and edit many tasks at once, reducing repetitive manual updates common in other project management tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Figma and third-party integrations$q$, $q$Height integrated with tools including Figma to connect design and engineering workflows.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Fast, keyboard-driven interface that was widely praised as snappier than competitors like Jira and Asana$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$AI features integrated directly into core workflows rather than bolted on separately$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Unusually generous free tier including full AI features for up to 5 users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Founder had prior relevant experience building product at Stripe$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Well-funded by a respected investor (Redpoint Ventures) before shutting down$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$The service has permanently shut down as of September 24, 2025, and is no longer available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$No successor product or acquirer continued the platform after closure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Existing customers had to migrate their project data to another tool$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Smaller company and team size than large incumbents like Atlassian, creating sustainability risk that ultimately materialized$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$No public option to export or continue using historical Height data through the original service today$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Is Height.app still available?$q$, $q$No. Height announced it was shutting down in March 2025 and the service permanently stopped operating on September 24, 2025. It is no longer available for new or existing customers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Who founded Height?$q$, $q$Height was founded in 2018 by Michael Villar, who previously co-founded Kickoff (acquired by Stripe in 2013) and worked as a product designer and engineer at Stripe.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Was Height acquired?$q$, $q$There is no public record of Height being acquired by another company. It was discontinued outright by its own team rather than absorbed into another product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$How much did Height cost before it shut down?$q$, $q$Height offered a free plan for up to 5 users, with paid tiers at 8.50 dollars per user per month for Teams and 14 dollars per user per month for Business.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$What made Height different from Jira or Asana?$q$, $q$Height emphasized interface speed with keyboard-first, command-palette navigation and deeply integrated AI features, including AI-driven bug triage, rather than positioning AI as a bolt-on add-on.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$What should I use instead of Height now?$q$, $q$Since Height has shut down, former users have migrated to alternatives such as Linear, Jira, Asana or ClickUp, depending on team size and workflow needs.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Fast-moving software engineering teams (historical)$q$, $q$Engineering teams used Height for issue tracking and sprint planning, valuing its speed and keyboard-driven workflow over heavier tools like Jira.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$AI-assisted bug triage (historical)$q$, $q$Teams used Height's AI to automatically assess and route incoming bug reports, reducing manual triage overhead for engineering managers.$q$, $q$Engineering managers and QA teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Startup project management (historical)$q$, $q$Early-stage startups used Height's generous free tier to manage projects and tasks without paying for a full project management suite.$q$, $q$Startups and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Free (historical)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 5 users","Unlimited tasks and lists","Full AI features included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Teams (historical)$q$, $q$$8.50/user/month$q$, $q$Monthly$q$, NULL, $q$["Expanded team collaboration features","AI assistant"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Business (historical)$q$, $q$$14/user/month$q$, $q$Monthly$q$, NULL, $q$["Advanced administration and permissions","Full AI feature set","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Height was a fast, keyboard-driven project management and issue-tracking tool founded in 2018 by Michael Villar, a former Stripe product designer and engineer, and headquartered in New York City. The company raised roughly 18.3 million dollars in total funding, including a 14 million dollar Series A led by Redpoint Ventures.$q$, $q$Height is no longer operating. The company announced its shutdown in March 2025 and ceased service permanently on September 24, 2025, after roughly seven years in business. There is no public record of an acquisition; the product was discontinued outright.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Height was built around speed: command-palette navigation, bulk editing and keyboard shortcuts throughout the interface, positioned as noticeably faster than tools like Jira and Asana. Its most distinctive feature was a built-in AI assistant with full project context that could summarize task history, draft descriptions and surface blockers.$q$, $q$For engineering teams, Height also offered AI-driven bug triage, automatically assessing incoming bug reports for priority and routing them to the right engineer or team.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Before its shutdown, Height offered a generous free plan for up to 5 users with unlimited tasks, lists and full AI features included. Paid tiers were priced at 8.50 dollars per user per month for Teams and 14 dollars per user per month for Business.$q$, $q$This pricing is historical only. Height is no longer accepting new signups or providing service; anyone researching it today should look at active alternatives such as Linear, Jira or Asana instead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
