INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$One-line-of-code LLM logging$q$, $q$A lightweight proxy or SDK integration captures every prompt, completion, latency and cost figure across LLM providers with minimal setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$AI gateway with multi-provider routing$q$, $q$Traffic can be automatically routed or failed over across multiple LLM providers and models to maintain uptime and manage cost.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$HQL (Helicone Query Language)$q$, $q$A dedicated query language, available on paid tiers, for advanced analysis of logged AI request and cost data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Cost and token tracking$q$, $q$Per-request cost is automatically calculated across models and providers, giving teams visibility into LLM spend without manual tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Evaluation tooling$q$, $q$Built-in tools for testing and scoring model outputs help teams catch regressions in quality before they reach production.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Alerting on anomalies and cost spikes$q$, $q$Configurable alerts notify teams of unusual latency, error rates or cost spikes across their LLM traffic.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$SOC-2 and HIPAA compliance$q$, $q$Available on the Team and Enterprise tiers for organizations with regulatory or security compliance requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Open-source, self-hostable codebase$q$, $q$The full platform is open source on GitHub, giving developers transparency and the option to self-host rather than rely solely on Helicone's cloud offering.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Genuinely open source, with full platform code available on GitHub$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Generous free Hobby tier covering 10,000 requests a month with no cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Functions as both an observability platform and an AI gateway with routing and fallback$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$SOC-2 and HIPAA compliance available for regulated and enterprise customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Backed by Y Combinator credibility and now Mintlify's resources post-acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Now in maintenance mode following the Mintlify acquisition, meaning independent roadmap development has slowed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Advanced querying via HQL and unlimited seats require upgrading to the Pro tier or above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Data retention on lower tiers is short (7 days on Hobby, 1 month on Pro), which may not suit teams needing longer audit trails$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Team and Enterprise pricing is a significant jump from the Pro tier for compliance-focused organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$As with any proxy-based observability tool, routing LLM traffic through Helicone adds a dependency in the request path$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$What does Helicone do?$q$, $q$Helicone is an LLM observability platform and AI gateway that logs, monitors and helps optimize the cost and performance of applications built on LLM providers like OpenAI and Anthropic, with a single line of code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Is Helicone free?$q$, $q$Yes, Helicone's Hobby tier is free and includes 10,000 requests a month, 1 GB of log storage and 7-day data retention. Paid plans start at 79 dollars a month for the Pro tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Is Helicone open source?$q$, $q$Yes, Helicone's full platform code is open source and publicly available on GitHub, which also allows for self-hosting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Who founded Helicone?$q$, $q$Helicone was founded in 2023 by Justin Torre and Cole Gottdank, and it went through Y Combinator's Winter 2023 (W23) batch.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Was Helicone acquired?$q$, $q$Yes, Helicone was acquired by Mintlify, the AI-era documentation and knowledge infrastructure company, in a deal announced in March 2026. Helicone now operates in maintenance mode under Mintlify.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Does Helicone support routing between multiple LLM providers?$q$, $q$Yes, Helicone functions as an AI gateway that can route traffic and handle fallback across multiple LLM providers and models, in addition to its observability and logging features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Production LLM cost and performance monitoring$q$, $q$An engineering team integrates Helicone to track latency, error rates and per-request cost across all the OpenAI and Anthropic calls their application makes in production.$q$, $q$Engineering teams building AI products$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Multi-provider AI gateway and fallback$q$, $q$A company routes LLM traffic through Helicone's AI gateway to automatically fail over to a backup provider or model if their primary provider experiences an outage.$q$, $q$AI infrastructure and platform engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Compliance-driven LLM observability$q$, $q$A regulated enterprise uses Helicone's Team or Enterprise tier for SOC-2 and HIPAA-compliant logging and auditing of AI interactions involving sensitive data.$q$, $q$Enterprises in regulated industries such as healthcare and finance$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["10,000 requests/month","1 GB storage","1 seat","7-day data retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Pro$q$, $q$$79/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited seats","Alerting and reporting","HQL query language","1-month data retention","Usage-based billing beyond base tier"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Team$q$, $q$$799/month$q$, $q$Monthly$q$, NULL, $q$["Up to 5 organizations","SOC-2 and HIPAA compliance","3-month data retention","Higher log ingestion rate"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$Enterprise$q$, $q$Custom$q$, $q$Contact for pricing$q$, NULL, $q$["Custom MSA","SAML SSO","On-premises deployment","Forever data retention","Volume discounts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Helicone is an open-source LLM observability platform and AI gateway founded in 2023 by Justin Torre and Cole Gottdank, and a graduate of Y Combinator's Winter 2023 batch. It gives developers a unified way to log, monitor, evaluate and optimize the cost and performance of applications built on OpenAI, Anthropic and other LLM providers, with source code publicly available on GitHub.$q$, $q$In March 2026, Helicone was acquired by Mintlify, the AI-era documentation and knowledge-infrastructure company, after growing to process 14.2 trillion tokens for more than 16,000 organizations as an independent company. Helicone now operates in maintenance mode, continuing security updates and new model support under Mintlify.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Helicone functions as both a passive observability layer and an active AI gateway: it logs every prompt, completion, latency figure and calculated cost across LLM providers, and it can route and fall back traffic across multiple providers or models. Advanced users get access to HQL, Helicone's dedicated query language for analyzing logged AI traffic.$q$, $q$The platform also includes evaluation tooling to test and score model outputs, alerting for cost spikes or anomalies, and compliance features like SOC-2 and HIPAA support on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Helicone's free Hobby tier includes 10,000 requests a month, 1 GB of storage and a single seat, with 7-day data retention. Paid tiers scale from Pro at 79 dollars a month (unlimited seats, HQL, 1-month retention) to Team at 799 dollars a month (SOC-2 and HIPAA, 3-month retention) up to custom-priced Enterprise with SAML SSO, on-premises deployment and forever retention.$q$, $q$Discounts are available for early-stage startups (50 percent off the first year), non-profits, open-source projects (100-dollar annual credit) and students.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5b558345-f62d-4c17-b8c6-88e78d8300a2', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
